   1→/* ==========================================================================
   2→   Buy Property Services - Main Custom Stylesheet
   3→   Shopify Dawn Theme Fork | UK Property Services Marketplace
   4→   ========================================================================== */
   5→
   6→/* --------------------------------------------------------------------------
   7→   1. Google Fonts Import
   8→   -------------------------------------------------------------------------- */
   9→@import url('https://fonts.googleapis.com/css2?family=Poppins:wght@300;400;500;600;700;800&display=swap');
  10→
  11→/* --------------------------------------------------------------------------
  12→   2. CSS Custom Properties (Brand Palette)
  13→   -------------------------------------------------------------------------- */
  14→:root {
  15→  /* Brand Colors */
  16→  --color-green-dark: #1A4D2E;
  17→  --color-green-dark-rgb: 26, 77, 46;
  18→  --color-orange: #E8922A;
  19→  --color-orange-rgb: 232, 146, 42;
  20→  --color-olive: #8FB339;
  21→  --color-olive-rgb: 143, 179, 57;
  22→  --color-cream: #F5F0E1;
  23→  --color-cream-rgb: 245, 240, 225;
  24→  --color-tan: #C4B699;
  25→  --color-tan-rgb: 196, 182, 153;
  26→  --color-white: #FFFFFF;
  27→  --color-dark: #1A1A1A;
  28→
  29→  /* Semantic Aliases */
  30→  --color-primary: var(--color-green-dark);
  31→  --color-accent: var(--color-orange);
  32→  --color-secondary: var(--color-olive);
  33→  --color-background: var(--color-cream);
  34→  --color-border: var(--color-tan);
  35→  --color-text: var(--color-dark);
  36→
  37→  /* Typography */
  38→  --font-family: 'Poppins', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  39→  --font-weight-light: 300;
  40→  --font-weight-regular: 400;
  41→  --font-weight-medium: 500;
  42→  --font-weight-semibold: 600;
  43→  --font-weight-bold: 700;
  44→  --font-weight-extrabold: 800;
  45→
  46→  /* Spacing */
  47→  --section-padding-mobile: 3rem 1.25rem;
  48→  --section-padding-tablet: 4rem 2rem;
  49→  --section-padding-desktop: 5rem 3rem;
  50→
  51→  /* Transitions */
  52→  --transition-base: 0.3s ease;
  53→
  54→  /* Shadows */
  55→  --shadow-sm: 0 2px 8px rgba(0, 0, 0, 0.06);
  56→  --shadow-md: 0 4px 16px rgba(0, 0, 0, 0.08);
  57→  --shadow-lg: 0 8px 32px rgba(0, 0, 0, 0.12);
  58→  --shadow-glow-green: 0 0 20px rgba(var(--color-green-dark-rgb), 0.3);
  59→  --shadow-glow-orange: 0 0 20px rgba(var(--color-orange-rgb), 0.3);
  60→
  61→  /* Border Radius */
  62→  --radius-sm: 6px;
  63→  --radius-md: 10px;
  64→  --radius-lg: 16px;
  65→  --radius-full: 50%;
  66→}
  67→
  68→/* --------------------------------------------------------------------------
  69→   3. Dawn Theme Global Overrides
  70→   -------------------------------------------------------------------------- */
  71→html {
  72→  scroll-behavior: smooth;
  73→  font-size: 16px;
  74→}
  75→
  76→body,
  77→.shopify-section,
  78→.shopify-section-group-header-group,
  79→.shopify-section-group-footer-group {
  80→  font-family: var(--font-family);
  81→  color: var(--color-text);
  82→}
  83→
  84→body {
  85→  background-color: var(--color-cream);
  86→  -webkit-font-smoothing: antialiased;
  87→  -moz-osx-font-smoothing: grayscale;
  88→}
  89→
  90→/* Override Dawn CSS variables where safe */
  91→:root,
  92→:root .color-background-1 {
  93→  --color-foreground: 26, 26, 26;
  94→  --color-background: 245, 240, 225;
  95→  --gradient-background: var(--color-cream);
  96→}
  97→
  98→h1, h2, h3, h4, h5, h6,
  99→.h0, .h1, .h2, .h3, .h4, .h5, .h6 {
 100→  font-family: var(--font-family);
 101→  font-weight: var(--font-weight-bold);
 102→  color: var(--color-dark);
 103→  line-height: 1.2;
 104→}
 105→
 106→a {
 107→  transition: color var(--transition-base), opacity var(--transition-base);
 108→}
 109→
 110→img {
 111→  max-width: 100%;
 112→  height: auto;
 113→}
 114→
 115→/* --------------------------------------------------------------------------
 116→   4. Header Styles
 117→   -------------------------------------------------------------------------- */
 118→.bps-header,
 119→.section-header {
 120→  background-color: var(--color-green-dark);
 121→  color: var(--color-white);
 122→  position: sticky;
 123→  top: 0;
 124→  z-index: 1000;
 125→  transition: background-color var(--transition-base), box-shadow var(--transition-base);
 126→}
 127→
 128→.bps-header a,
 129→.section-header .header__heading-link,
 130→.section-header .header__menu-item,
 131→.section-header .list-menu__item--link {
 132→  color: var(--color-white);
 133→  text-decoration: none;
 134→}
 135→
 136→.bps-header a:hover,
 137→.section-header .header__menu-item:hover,
 138→.section-header .list-menu__item--link:hover {
 139→  color: var(--color-orange);
 140→}
 141→
 142→/* Header icon buttons (cart, search, menu) */
 143→.section-header .header__icon,
 144→.section-header .header__icon .icon {
 145→  color: var(--color-white);
 146→  fill: var(--color-white);
 147→}
 148→
 149→.section-header .header__icon:hover {
 150→  color: var(--color-orange);
 151→}
 152→
 153→/* Cart count badge */
 154→.section-header .cart-count-bubble {
 155→  background-color: var(--color-orange);
 156→  color: var(--color-white);
 157→}
 158→
 159→/* Transparent header on homepage hero */
 160→.header--transparent {
 161→  background-color: transparent;
 162→  position: absolute;
 163→  width: 100%;
 164→}
 165→
 166→.header--transparent.header--scrolled {
 167→  background-color: var(--color-green-dark);
 168→  position: sticky;
 169→  box-shadow: 0 2px 12px rgba(0, 0, 0, 0.15);
 170→}
 171→
 172→/* Mobile menu drawer */
 173→.menu-drawer {
 174→  background-color: var(--color-green-dark);
 175→  color: var(--color-white);
 176→}
 177→
 178→.menu-drawer a,
 179→.menu-drawer .menu-drawer__menu-item {
 180→  color: var(--color-white);
 181→  font-family: var(--font-family);
 182→}
 183→
 184→.menu-drawer a:hover,
 185→.menu-drawer .menu-drawer__menu-item:hover {
 186→  color: var(--color-orange);
 187→}
 188→
 189→.menu-drawer__close-button .icon {
 190→  color: var(--color-white);
 191→}
 192→
 193→/* --------------------------------------------------------------------------
 194→   5. Hero Banner
 195→   -------------------------------------------------------------------------- */
 196→.hero-banner {
 197→  position: relative;
 198→  width: 100%;
 199→  height: 70vh;
 200→  min-height: 480px;
 201→  display: flex;
 202→  align-items: center;
 203→  justify-content: center;
 204→  text-align: center;
 205→  overflow: hidden;
 206→  background-size: cover;
 207→  background-position: center;
 208→  background-repeat: no-repeat;
 209→}
 210→
 211→.hero-banner::after {
 212→  content: '';
 213→  position: absolute;
 214→  inset: 0;
 215→  background: linear-gradient(
 216→    to top,
 217→    rgba(0, 0, 0, 0.65) 0%,
 218→    rgba(0, 0, 0, 0.25) 50%,
 219→    rgba(0, 0, 0, 0.1) 100%
 220→  );
 221→  z-index: 1;
 222→}
 223→
 224→.hero-banner__content {
 225→  position: relative;
 226→  z-index: 2;
 227→  max-width: 720px;
 228→  padding: 1.5rem;
 229→}
 230→
 231→.hero-banner__heading {
 232→  font-size: clamp(1.75rem, 5vw, 3.5rem);
 233→  font-weight: var(--font-weight-extrabold);
 234→  color: var(--color-white);
 235→  text-shadow: 0 2px 12px rgba(0, 0, 0, 0.4);
 236→  margin-bottom: 1rem;
 237→  line-height: 1.15;
 238→}
 239→
 240→.hero-banner__subheading {
 241→  font-size: clamp(0.95rem, 2vw, 1.25rem);
 242→  color: rgba(255, 255, 255, 0.9);
 243→  font-weight: var(--font-weight-regular);
 244→  margin-bottom: 2rem;
 245→  text-shadow: 0 1px 6px rgba(0, 0, 0, 0.3);
 246→}
 247→
 248→/* Toggle buttons: I am Selling / I am Renting */
 249→.hero-banner__toggle {
 250→  display: inline-flex;
 251→  gap: 0;
 252→  border-radius: var(--radius-lg);
 253→  overflow: hidden;
 254→  border: 2px solid var(--color-white);
 255→  margin-bottom: 1.5rem;
 256→}
 257→
 258→.hero-banner__toggle-btn {
 259→  padding: 0.85rem 1.75rem;
 260→  font-family: var(--font-family);
 261→  font-size: 1rem;
 262→  font-weight: var(--font-weight-semibold);
 263→  border: none;
 264→  cursor: pointer;
 265→  transition: background-color var(--transition-base), color var(--transition-base);
 266→  background-color: transparent;
 267→  color: var(--color-white);
 268→  min-height: 54px;
 269→}
 270→
 271→.hero-banner__toggle-btn:hover {
 272→  background-color: rgba(255, 255, 255, 0.15);
 273→}
 274→
 275→.hero-banner__toggle-btn.is-active {
 276→  background-color: var(--color-orange);
 277→  color: var(--color-white);
 278→}
 279→
 280→.hero-banner__cta {
 281→  display: inline-block;
 282→  margin-top: 0.5rem;
 283→}
 284→
 285→@media (min-width: 990px) {
 286→  .hero-banner {
 287→    height: 100vh;
 288→    min-height: 600px;
 289→  }
 290→}
 291→
 292→/* --------------------------------------------------------------------------
 293→   6. Service Grid
 294→   -------------------------------------------------------------------------- */
 295→.service-grid {
 296→  display: grid;
 297→  grid-template-columns: 1fr;
 298→  gap: 1.25rem;
 299→  padding: 0;
 300→}
 301→
 302→.service-grid__card {
 303→  background: rgba(255, 255, 255, 0.85);
 304→  backdrop-filter: blur(10px);
 305→  -webkit-backdrop-filter: blur(10px);
 306→  border: 1px solid rgba(var(--color-tan-rgb), 0.4);
 307→  border-radius: var(--radius-lg);
 308→  padding: 1.75rem 1.5rem;
 309→  text-align: center;
 310→  transition:
 311→    transform var(--transition-base),
 312→    box-shadow var(--transition-base),
 313→    border-color var(--transition-base);
 314→  box-shadow: var(--shadow-sm);
 315→}
 316→
 317→.service-grid__card:hover {
 318→  transform: translateY(-8px);
 319→  box-shadow: var(--shadow-lg), 0 0 24px rgba(var(--color-green-dark-rgb), 0.12);
 320→  border-color: var(--color-olive);
 321→}
 322→
 323→.service-grid__icon {
 324→  width: 64px;
 325→  height: 64px;
 326→  margin: 0 auto 1rem;
 327→  display: flex;
 328→  align-items: center;
 329→  justify-content: center;
 330→  background-color: rgba(var(--color-green-dark-rgb), 0.08);
 331→  border-radius: var(--radius-full);
 332→}
 333→
 334→.service-grid__icon img,
 335→.service-grid__icon svg {
 336→  width: 32px;
 337→  height: 32px;
 338→}
 339→
 340→.service-grid__title {
 341→  font-size: 1.125rem;
 342→  font-weight: var(--font-weight-semibold);
 343→  color: var(--color-dark);
 344→  margin-bottom: 0.5rem;
 345→}
 346→
 347→.service-grid__price {
 348→  font-size: 0.9rem;
 349→  color: var(--color-orange);
 350→  font-weight: var(--font-weight-semibold);
 351→  margin-bottom: 1.25rem;
 352→}
 353→
 354→.service-grid__price span {
 355→  font-size: 1.35rem;
 356→  font-weight: var(--font-weight-bold);
 357→}
 358→
 359→.service-grid__cta {
 360→  display: block;
 361→  width: 100%;
 362→  min-height: 54px;
 363→}
 364→
 365→@media (min-width: 750px) {
 366→  .service-grid {
 367→    grid-template-columns: repeat(2, 1fr);
 368→    gap: 1.5rem;
 369→  }
 370→}
 371→
 372→@media (min-width: 990px) {
 373→  .service-grid {
 374→    grid-template-columns: repeat(3, 1fr);
 375→    gap: 2rem;
 376→  }
 377→
 378→  .service-grid__cta {
 379→    width: auto;
 380→    display: inline-block;
 381→  }
 382→}
 383→
 384→/* --------------------------------------------------------------------------
 385→   7. Trust Bar
 386→   -------------------------------------------------------------------------- */
 387→.trust-bar {
 388→  display: flex;
 389→  gap: 1rem;
 390→  overflow-x: auto;
 391→  scroll-snap-type: x mandatory;
 392→  -webkit-overflow-scrolling: touch;
 393→  padding-bottom: 0.5rem;
 394→  scrollbar-width: thin;
 395→}
 396→
 397→.trust-bar::-webkit-scrollbar {
 398→  height: 4px;
 399→}
 400→
 401→.trust-bar::-webkit-scrollbar-thumb {
 402→  background: var(--color-tan);
 403→  border-radius: 4px;
 404→}
 405→
 406→.trust-bar__item {
 407→  flex: 0 0 auto;
 408→  min-width: 200px;
 409→  scroll-snap-align: start;
 410→  background: var(--color-white);
 411→  border-radius: var(--radius-md);
 412→  padding: 1.25rem 1.5rem;
 413→  text-align: center;
 414→  box-shadow: var(--shadow-sm);
 415→}
 416→
 417→.trust-bar__stat {
 418→  font-size: 1.75rem;
 419→  font-weight: var(--font-weight-bold);
 420→  color: var(--color-green-dark);
 421→  line-height: 1;
 422→  margin-bottom: 0.35rem;
 423→}
 424→
 425→.trust-bar__label {
 426→  font-size: 0.85rem;
 427→  color: var(--color-dark);
 428→  opacity: 0.7;
 429→}
 430→
 431→.trust-bar__stars {
 432→  color: var(--color-orange);
 433→  font-size: 1.1rem;
 434→  letter-spacing: 2px;
 435→  margin-bottom: 0.35rem;
 436→}
 437→
 438→@media (min-width: 750px) {
 439→  .trust-bar {
 440→    overflow-x: visible;
 441→    flex-wrap: wrap;
 442→    justify-content: center;
 443→  }
 444→
 445→  .trust-bar__item {
 446→    flex: 0 1 auto;
 447→    min-width: 180px;
 448→  }
 449→}
 450→
 451→/* --------------------------------------------------------------------------
 452→   8. Process Timeline
 453→   -------------------------------------------------------------------------- */
 454→.process-timeline {
 455→  position: relative;
 456→  display: flex;
 457→  flex-direction: column;
 458→  gap: 2rem;
 459→  padding-left: 2.5rem;
 460→}
 461→
 462→/* Vertical connecting line (mobile) */
 463→.process-timeline::before {
 464→  content: '';
 465→  position: absolute;
 466→  left: 15px;
 467→  top: 0;
 468→  bottom: 0;
 469→  width: 3px;
 470→  background-color: var(--color-tan);
 471→  border-radius: 2px;
 472→}
 473→
 474→.process-timeline__step {
 475→  position: relative;
 476→  padding: 0;
 477→}
 478→
 479→.process-timeline__number {
 480→  position: absolute;
 481→  left: -2.5rem;
 482→  top: 0;
 483→  width: 32px;
 484→  height: 32px;
 485→  background-color: var(--color-green-dark);
 486→  color: var(--color-white);
 487→  border-radius: var(--radius-full);
 488→  display: flex;
 489→  align-items: center;
 490→  justify-content: center;
 491→  font-size: 0.85rem;
 492→  font-weight: var(--font-weight-bold);
 493→  z-index: 1;
 494→}
 495→
 496→.process-timeline__icon {
 497→  font-size: 1.5rem;
 498→  margin-bottom: 0.5rem;
 499→}
 500→
 501→.process-timeline__title {
 502→  font-size: 1rem;
 503→  font-weight: var(--font-weight-semibold);
 504→  color: var(--color-dark);
 505→  margin-bottom: 0.25rem;
 506→}
 507→
 508→.process-timeline__desc {
 509→  font-size: 0.875rem;
 510→  color: var(--color-dark);
 511→  opacity: 0.7;
 512→  line-height: 1.5;
 513→}
 514→
 515→@media (min-width: 990px) {
 516→  .process-timeline {
 517→    flex-direction: row;
 518→    padding-left: 0;
 519→    gap: 0;
 520→    justify-content: space-between;
 521→    align-items: flex-start;
 522→  }
 523→
 524→  /* Horizontal connecting line (desktop) */
 525→  .process-timeline::before {
 526→    left: 0;
 527→    right: 0;
 528→    top: 15px;
 529→    bottom: auto;
 530→    width: auto;
 531→    height: 3px;
 532→  }
 533→
 534→  .process-timeline__step {
 535→    flex: 1;
 536→    text-align: center;
 537→    padding: 3rem 1rem 0;
 538→  }
 539→
 540→  .process-timeline__number {
 541→    left: 50%;
 542→    top: 0;
 543→    transform: translateX(-50%);
 544→  }
 545→}
 546→
 547→/* --------------------------------------------------------------------------
 548→   9. Service Card Snippet (.card-service)
 549→   -------------------------------------------------------------------------- */
 550→.card-service {
 551→  background: rgba(255, 255, 255, 0.85);
 552→  backdrop-filter: blur(10px);
 553→  -webkit-backdrop-filter: blur(10px);
 554→  border: 1px solid rgba(var(--color-tan-rgb), 0.4);
 555→  border-radius: var(--radius-lg);
 556→  overflow: hidden;
 557→  transition:
 558→    transform var(--transition-base),
 559→    box-shadow var(--transition-base),
 560→    border-color var(--transition-base);
 561→  box-shadow: var(--shadow-sm);
 562→}
 563→
 564→.card-service:hover {
 565→  transform: translateY(-4px);
 566→  box-shadow: var(--shadow-md);
 567→  border-color: var(--color-olive);
 568→  animation: pulse-glow 2s ease-in-out infinite;
 569→}
 570→
 571→.card-service__image {
 572→  width: 100%;
 573→  aspect-ratio: 16 / 10;
 574→  object-fit: cover;
 575→}
 576→
 577→.card-service__body {
 578→  padding: 1.25rem 1.5rem;
 579→}
 580→
 581→.card-service__title {
 582→  font-size: 1.05rem;
 583→  font-weight: var(--font-weight-semibold);
 584→  margin-bottom: 0.5rem;
 585→}
 586→
 587→.card-service__price-badge {
 588→  display: inline-block;
 589→  background-color: var(--color-orange);
 590→  color: var(--color-white);
 591→  padding: 0.3rem 0.85rem;
 592→  border-radius: var(--radius-sm);
 593→  font-size: 0.85rem;
 594→  font-weight: var(--font-weight-bold);
 595→  margin-bottom: 0.75rem;
 596→}
 597→
 598→.card-service__price-badge--starting {
 599→  background-color: rgba(var(--color-orange-rgb), 0.12);
 600→  color: var(--color-orange);
 601→}
 602→
 603→.card-service__desc {
 604→  font-size: 0.875rem;
 605→  color: var(--color-dark);
 606→  opacity: 0.7;
 607→  line-height: 1.5;
 608→  margin-bottom: 1rem;
 609→}
 610→
 611→.card-service__actions {
 612→  display: flex;
 613→  flex-direction: column;
 614→  gap: 0.5rem;
 615→}
 616→
 617→.card-service__actions .btn-primary {
 618→  width: 100%;
 619→  min-height: 54px;
 620→}
 621→
 622→@media (min-width: 750px) {
 623→  .card-service__actions {
 624→    flex-direction: row;
 625→  }
 626→
 627→  .card-service__actions .btn-primary {
 628→    width: auto;
 629→  }
 630→}
 631→
 632→/* --------------------------------------------------------------------------
 633→   10. Animations
 634→   -------------------------------------------------------------------------- */
 635→@keyframes fadeInUp {
 636→  from {
 637→    opacity: 0;
 638→    transform: translateY(30px);
 639→  }
 640→  to {
 641→    opacity: 1;
 642→    transform: translateY(0);
 643→  }
 644→}
 645→
 646→@keyframes pulse-glow {
 647→  0%, 100% {
 648→    box-shadow: var(--shadow-md), 0 0 0 0 rgba(var(--color-green-dark-rgb), 0);
 649→  }
 650→  50% {
 651→    box-shadow: var(--shadow-md), 0 0 18px 2px rgba(var(--color-green-dark-rgb), 0.15);
 652→  }
 653→}
 654→
 655→@keyframes float-orb {
 656→  0%, 100% {
 657→    transform: translateY(0) translateX(0);
 658→  }
 659→  25% {
 660→    transform: translateY(-15px) translateX(8px);
 661→  }
 662→  50% {
 663→    transform: translateY(-8px) translateX(-5px);
 664→  }
 665→  75% {
 666→    transform: translateY(-20px) translateX(3px);
 667→  }
 668→}
 669→
 670→/* Scroll reveal */
 671→.reveal-on-scroll {
 672→  opacity: 0;
 673→  transform: translateY(30px);
 674→  transition: opacity 0.6s ease, transform 0.6s ease;
 675→}
 676→
 677→.reveal-on-scroll.is-visible {
 678→  opacity: 1;
 679→  transform: translateY(0);
 680→}
 681→
 682→/* Decorative floating orb */
 683→.floating-orb {
 684→  position: absolute;
 685→  border-radius: var(--radius-full);
 686→  opacity: 0.15;
 687→  pointer-events: none;
 688→  animation: float-orb 8s ease-in-out infinite;
 689→}
 690→
 691→/* Respect reduced motion */
 692→@media (prefers-reduced-motion: reduce) {
 693→  *,
 694→  *::before,
 695→  *::after {
 696→    animation-duration: 0.01ms !important;
 697→    animation-iteration-count: 1 !important;
 698→    transition-duration: 0.01ms !important;
 699→    scroll-behavior: auto !important;
 700→  }
 701→
 702→  .reveal-on-scroll {
 703→    opacity: 1;
 704→    transform: none;
 705→  }
 706→}
 707→
 708→/* --------------------------------------------------------------------------
 709→   11. Buttons
 710→   -------------------------------------------------------------------------- */
 711→.btn-primary {
 712→  display: inline-flex;
 713→  align-items: center;
 714→  justify-content: center;
 715→  background-color: var(--color-orange);
 716→  color: var(--color-white);
 717→  font-family: var(--font-family);
 718→  font-size: 0.95rem;
 719→  font-weight: var(--font-weight-semibold);
 720→  padding: 0.8rem 1.75rem;
